{
  "family": "Larock Indole Synthesis",
  "candidate": {
    "substrate_smiles": [
      "Nc1ccccc1I",
      "CCC#CCC"
    ],
    "product_smiles": [
      "CCC1=C(CC)c2ccccc2N1"
    ],
    "optional_reagent_smiles": [
      "[Pd+2].[O-]C(=O)C.[O-]C(=O)C",
      "[Li+].[Cl-]",
      "CC(=O)[O-].[K+]"
    ],
    "rationale": "This example shows the palladium-catalyzed heteroannulation of the simplest o-haloaniline, 2-iodoaniline, with a simple, symmetrical internal alkyne, 3-hexyne. This reaction forms a 2,3-disubstituted indole, which is the characteristic product of this transformation. The reactants are small, acyclic (where possible), and lack complex functional groups, making it a clear and canonical representation of the Larock Indole Synthesis.",
    "collision_avoidance_note": "This example avoids using terminal alkynes, which could be confused with Sonogashira couplings. It also avoids complex aromatic systems or additional functional groups that might trigger other named reaction classifiers. The use of a simple o-iodoaniline and a symmetrical internal alkyne focuses specifically on the indole ring formation characteristic of the Larock synthesis."
  }
}
